sql:
SELECT COUNT(session_id) AS total_sessions
FROM player_sessions
WHERE player_id = 1;

SELECT MAX(score) AS highest_score
FROM player_sessions
WHERE level_id = 1;

SELECT COUNT(session_id) AS total_sessions
FROM player_sessions
WHERE player_id = 0;

SELECT level_name, max_score
FROM levels
ORDER BY max_score DESC;

SELECT AVG(analytics_value) AS average_score
FROM session_analytics
WHERE analytics_type = 'Score Achieved';

